// Управление состояниями ИИ-ментора

// Функции работы с Static Data
function getWorkflowData() {
  return $getWorkflowStaticData('global');
}

function getMentorData() {
  const allData = getWorkflowData();
  if (!allData.mentor_states) {
    allData.mentor_states = {};
  }
  return allData.mentor_states;
}

function getUserState(chatId) {
  const mentorData = getMentorData();
  if (!mentorData[chatId]) {
    mentorData[chatId] = {
      stage: 'greeting',
      goal: '',
      level: '',
      plan: [],
      sentConcepts: [],
      currentTopicIndex: 0,
      currentConceptIndex: 0,
      dialogHistory: [],
      lastUpdated: new Date().toISOString()
    };
  }
  return mentorData[chatId];
}

function saveUserState(chatId, state) {
  const mentorData = getMentorData();
  mentorData[chatId] = state;
  mentorData[chatId].lastUpdated = new Date().toISOString();
  return true;
}

function addToHistory(chatId, role, content) {
  const userState = getUserState(chatId);
  if (!userState.dialogHistory) userState.dialogHistory = [];
  userState.dialogHistory.push({ role, content, timestamp: new Date().toISOString() });
}

// Получаем данные из Telegram
const telegramData = items[0].json;
const message = telegramData.message.text.trim();
const chatId = telegramData.message.chat.id.toString();
const userName = telegramData.message.chat.first_name || 'Пользователь';

// Сохраняем chat_id в Static Data
const allData = getWorkflowData();
if (!allData.last_chat_ids) {
  allData.last_chat_ids = {};
}
allData.last_chat_ids[chatId] = new Date().toISOString();

// Обработка команды /reset
if (message === '/reset') {
  const allData = getWorkflowData();
  if (allData.mentor_states && allData.mentor_states[chatId]) {
    delete allData.mentor_states[chatId];
  }

  return [{
    json: {
      system_prompt: `Ты — персональный ИИ-ментор. Данные пользователя сброшены.`,
      user_prompt: `Скажи пользователю: "Все данные сброшены. Напишите 'привет' или '/start' для начала обучения."`,
      chat_id: chatId,
      stage: 'reset',
      user_name: userName
    }
  }];
}

// Получаем текущее состояние пользователя
const userState = getUserState(chatId);

// Добавляем сообщение пользователя в историю
addToHistory(chatId, 'user', message);

// Подготовка данных для AI Agent
let systemPrompt = '';
let userPrompt = '';

// Обработка команды /start
if (message === '/start') {
  userState.stage = 'greeting';
  userState.goal = '';
  userState.level = '';
  userState.plan = [];
  userState.sentConcepts = [];
  userState.dialogHistory = [];
}

// Логика по этапам
switch(userState.stage) {
  case 'greeting':
    systemPrompt = `Ты — дружелюбный персональный ИИ-ментор. Твоё имя — Наставник. Поприветствуй пользователя и задай первый вопрос.`;
    userPrompt = `Поприветствуй пользователя ${userName} и спроси: "Чему бы ты хотел научиться в рамках работы над текущим учебным проектом или в рамках подготовки к собеседованию и трудоустройству?"`;
    userState.stage = 'waiting_goal';
    break;

  case 'waiting_goal':
    if (message.length < 3) {
      systemPrompt = `Ты — персональный ИИ-ментор. Пользователь дал слишком короткий ответ.`;
      userPrompt = `Пользователь ответил: "${message}". Вежливо попроси его уточнить, чему именно он хочет научиться.`;
    } else {
      userState.goal = message;
      userState.stage = 'waiting_level';
      systemPrompt = `Ты — персональный ИИ-ментор. Пользователь указал цель обучения. Теперь нужно узнать его текущий уровень.`;
      userPrompt = `Пользователь ${userName} хочет научиться: "${message}". 

Спроси его о текущем уровне знаний в этой области. Например:
1. Новичок (полный ноль, только начинаю)
2. Средний уровень (есть базовые знания, но хочу углубить)
3. Продвинутый (уже имею опыт, хочу систематизировать)`;
    }
    break;

  case 'waiting_level':
    userState.level = message;
    userState.stage = 'creating_plan';

    systemPrompt = `Ты — персональный ИИ-ментор. Создай учебный план на основе цели и уровня пользователя.

ТРЕБОВАНИЯ К ПЛАНУ:
1. Создай 3-5 тем для изучения
2. Каждая тема должна содержать 2-4 ключевых понятия
3. План должен соответствовать уровню пользователя: ${message}
4. Формат строго такой (пример):
Тема 1: REST API, HTTP методы, JSON
Тема 2: Аутентификация, JWT токены
Тема 3: Базы данных, SQL запросы, миграции

5. После плана напиши: "ГОТОВ_СОЗДАТЬ_ПЛАН"`;

    userPrompt = `Создай учебный план для цели: "${userState.goal}"
Уровень пользователя: "${message}"

Создай структурированный план в указанном формате.`;
    break;

  case 'creating_plan':
    const allDataPlan = getWorkflowData();
    const existingPlan = allDataPlan.mentor_states?.[chatId]?.plan;

    if (existingPlan && existingPlan.length > 0) {
      userState.plan = existingPlan;
      userState.stage = 'plan_ready';

      const planText = existingPlan.map((topic, i) => {
        const conceptsList = topic.concepts.map(c => `• ${c}`).join(', ');
        return `${i + 1}. ${topic.topic}: ${conceptsList}`;
      }).join('\n');

      systemPrompt = `Ты — персональный ИИ-ментор. Учебный план уже создан.`;
      userPrompt = `Учебный план создан!\n\n${planText}\n\nОтправьте "да" для начала обучения.`;
    } else {
      systemPrompt = `Ты — персональный ИИ-ментор. Создаю учебный план...`;
      userPrompt = `Создаю учебный план на основе ваших данных. Пожалуйста, подождите...`;
    }
    break;

  case 'plan_ready':
    if (!userState.plan || userState.plan.length === 0) {
      systemPrompt = `Ты — персональный ИИ-ментор. План еще не создан.`;
      userPrompt = `Скажи пользователю: "План еще не готов. Пожалуйста, подождите."`;
      break;
    }

    if (message.toLowerCase() === 'да' || 
        message.toLowerCase() === 'начать' || 
        message.toLowerCase() === 'start' ||
        message.toLowerCase() === 'go') {

      userState.stage = 'sending_posts';

      let nextConcept = '';
      if (userState.plan.length > 0 && userState.plan[0].concepts.length > 0) {
        nextConcept = userState.plan[0].concepts[0];
      }

      if (nextConcept) {
        systemPrompt = `Ты — персональный ИИ-ментор. Тебе нужно создавать поисковые запросы для учебных постов.

ВНИМАНИЕ! Если тебе нужна информация из интернета, ты должен вернуть ТОЛЬКО строку в формате:
tavily(query="краткий поисковый запрос")

ПРАВИЛА:
1. НИКАКОГО другого текста, только этот формат
2. Запрос должен быть на русском языке
3. Запрос должен относиться к понятию: ${nextConcept}`;

        userPrompt = `Начинаем обучение! Первое понятие для изучения: "${nextConcept}".

Создай поисковый запрос для получения информации по этому понятию.`;
      } else {
        systemPrompt = `Ты — персональный ИИ-ментор. В плане нет понятий.`;
        userPrompt = `Скажи пользователя: "В учебном плане нет понятий для изучения. Давайте создадим новый план."`;
      }
    } else if (message.toLowerCase() === 'нет' || message.toLowerCase() === 'no') {
      systemPrompt = `Ты — персональный ИИ-ментор. Пользователь отказался от плана.`;
      userPrompt = `Пользователь ответил "нет". Вежливо спроси, хочет ли он изменить цель обучения или у него есть вопросы.`;
    } else {
      systemPrompt = `Ты — персональный ИИ-ментор. Уточни у пользователя.`;
      userPrompt = `Пользователь ответил: "${message}". 

Уточни: "Хотите начать обучение по созданному плана? Ответьте 'да' или 'нет'."`;
    }
    break;

  case 'sending_posts':
    let nextConcept = null;
    let topicIndex = 0;
    let conceptIndex = 0;

    for (let i = 0; i < userState.plan.length; i++) {
      const topic = userState.plan[i];
      for (let j = 0; j < topic.concepts.length; j++) {
        const concept = topic.concepts[j];
        if (!userState.sentConcepts || !userState.sentConcepts.includes(concept)) {
          nextConcept = concept;
          topicIndex = i;
          conceptIndex = j;
          break;
        }
      }
      if (nextConcept) break;
    }

    if (nextConcept) {
      systemPrompt = `Ты — персональный ИИ-ментор. Твоя задача — создавать поисковые запросы для учебных постов.

ВНИМАНИЕ! Если тебе нужна информация из интернета, ты должен вернуть ТОЛЬКО строку в формате:
tavily(query="краткий поисковый запрос")

ПРАВИЛА:
1. НИКАКОГО другого текста, только этот формат
2. Запрос должен быть на русском языке
3. Запрос должен относиться к понятию: ${nextConcept}
4. Запрос должен быть понятным и конкретным`;

      userPrompt = `Создай поисковый запрос для получения информации по понятию: "${nextConcept}"`;
    } else {
      userState.stage = 'completed';
      systemPrompt = `Ты — персональный ИИ-ментор. Пользователь завершил все темы.`;
      userPrompt = `Все учебные темы пройдены! Поздравь пользователя ${userName} и спроси: "Что ты хочешь изучать дальше?"`;
    }
    break;

  case 'completed':
    userState.stage = 'waiting_goal';
    userState.goal = '';
    userState.level = '';
    userState.plan = [];
    userState.sentConcepts = [];

    systemPrompt = `Ты — персональный ИИ-ментор. Пользователь завершил один цикл обучения и хочет изучать что-то новое.`;
    userPrompt = `Поздравь пользователя ${userName} с завершением обучения! Теперь спроси: "Чему бы ты хотел научиться дальше?"`;
    break;

  default:
    systemPrompt = `Ты — персональный ИИ-ментор. Ответь пользователю соответствующим образом.`;
    userPrompt = `Пользователь ${userName} написал: "${message}". Ответь соответствующим образом.`;
}

// Сохраняем обновленное состояние
saveUserState(chatId, userState);

// Сохраняем chat_id в Static Data
const allDataFinal = getWorkflowData();
if (!allDataFinal.last_chat_ids) {
  allDataFinal.last_chat_ids = {};
}
allDataFinal.last_chat_ids[chatId] = new Date().toISOString();

// ВАЖНО: Создаем выходные данные с chat_id
const outputData = {
  // Поля для AI Agent
  system_prompt: systemPrompt,
  user_prompt: userPrompt,

  // chat_id ДОЛЖЕН быть здесь - проверяем
  chat_id: chatId,

  // Дополнительные данные
  original_message: message,
  current_stage: userState.stage,
  user_name: userName,
  user_goal: userState.goal,
  user_level: userState.level,
  user_plan: userState.plan
};

// Возвращаем данные
return [{ json: outputData }];

// Парсинг ответа от AI Agent - ИСПРАВЛЕННАЯ ВЕРСИЯ ДЛЯ MERGE NODE

console.log("=== Code in JavaScript1 (Merge version) ===");

// 1. Получаем данные от Merge node
// Merge node передает массив items, где:
// items[0] - данные от AI Agent (output)
// items[1] - данные от первой ноды (chat_id и другие поля)

if (items.length < 2) {
  console.log("❌ ERROR: Merge node не передал все данные");
  return [{
    json: {
      action: 'direct_response',
      telegram_text: "Ошибка системы. Пожалуйста, отправьте /start.",
      chat_id: "error_merge_failed"
    }
  }];
}

// 2. Берем ответ AI из первого элемента
const aiOutput = items[0];
const aiResponse = aiOutput.json.output || aiOutput.json.text || "";

console.log("Ответ AI:", aiResponse.substring(0, 100) + "...");

// 3. Берем chat_id из второго элемента
const firstNodeData = items[1];
const chatId = firstNodeData.json.chat_id;

console.log("Chat ID из первой ноды:", chatId);
console.log("Все поля из первой ноды:", Object.keys(firstNodeData.json));

if (!chatId) {
  console.log("❌ ERROR: chat_id не найден во втором элементе");
  return [{
    json: {
      action: 'direct_response',
      telegram_text: "Системная ошибка. Отправьте /start заново.",
      chat_id: "error_no_chat_id"
    }
  }];
}

// 4. ПРОВЕРЯЕМ, ЕСТЬ ЛИ "ГОТОВ_СОЗДАТЬ_ПЛАН"
const isPlanReady = aiResponse.includes("ГОТОВ_СОЗДАТЬ_ПЛАН") || 
                   aiResponse.includes("ГОТОВСОЗДАТЬПЛАН") ||
                   aiResponse.toLowerCase().includes("готов создать план");

// 5. Ищем tavily(query="...")
const tavilyRegex = /tavily\(query="([^"]+)"\)/;
const tavilyMatch = aiResponse.match(tavilyRegex);

if (tavilyMatch) {
  console.log("✅ Найден Tavily запрос:", tavilyMatch[1]);
  return [{
    json: {
      action: 'search',
      search_query: tavilyMatch[1],
      chat_id: chatId,
      original_response: aiResponse
    }
  }];
}

// 6. ПАРСИНГ УЧЕБНОГО ПЛАНА
const lines = aiResponse.split('\n');
let parsedPlan = [];
let currentTopic = null;

for (let line of lines) {
  line = line.trim();

  const topicMatch = line.match(/^Тема\s+\d+:?\s*(.+)/i);

  if (topicMatch) {
    if (currentTopic) {
      parsedPlan.push(currentTopic);
    }

    const content = topicMatch[1].trim();

    if (content.includes(':')) {
      const parts = content.split(':');
      const topicName = parts[0].trim();
      const conceptsStr = parts.slice(1).join(':').trim();
      const concepts = conceptsStr.split(',').map(c => c.trim()).filter(c => c);

      currentTopic = {
        topic: topicName,
        concepts: concepts
      };
    } else if (content.includes(',')) {
      const concepts = content.split(',').map(c => c.trim()).filter(c => c);
      currentTopic = {
        topic: `Тема ${parsedPlan.length + 1}`,
        concepts: concepts
      };
    } else {
      currentTopic = {
        topic: content,
        concepts: []
      };
    }
  }
  else if (currentTopic && (line.startsWith('-') || line.startsWith('•') || line.startsWith('*'))) {
    const concept = line.substring(1).trim();
    if (concept) {
      currentTopic.concepts.push(concept);
    }
  }
}

if (currentTopic) {
  parsedPlan.push(currentTopic);
}

// Проверяем, нашли ли план
if (parsedPlan.length > 0) {
  console.log("✅ Найден учебный план:", parsedPlan.length, "тем");

  const allData = $getWorkflowStaticData('global');

  if (!allData.mentor_states) {
    allData.mentor_states = {};
  }
  if (!allData.mentor_states[chatId]) {
    allData.mentor_states[chatId] = {};
  }

  allData.mentor_states[chatId].plan = parsedPlan;
  allData.mentor_states[chatId].stage = 'plan_ready';
  allData.mentor_states[chatId].sentConcepts = [];

  const planText = parsedPlan.map((topic, i) => {
    const conceptsList = topic.concepts.map(c => `• ${c}`).join('\n');
    return `${i + 1}. ${topic.topic}\n${conceptsList}`;
  }).join('\n\n');

  const responseText = `✅ Учебный план создан!\n\n${planText}\n\nОтправьте "да" для начала обучения.`;

  return [{
    json: {
      action: 'direct_response',
      telegram_text: responseText,
      chat_id: chatId,
      original_response: aiResponse
    }
  }];
}

// 7. Если нашли "ГОТОВ_СОЗДАТЬ_ПЛАН" но не распарсили план
if (isPlanReady) {
  console.log("📋 AI сообщил, что план готов");

  const allData = $getWorkflowStaticData('global');

  if (allData.mentor_states && allData.mentor_states[chatId] && allData.mentor_states[chatId].plan) {
    const plan = allData.mentor_states[chatId].plan;
    const planText = plan.map((topic, i) => {
      const conceptsList = topic.concepts.map(c => `• ${c}`).join('\n');
      return `${i + 1}. ${topic.topic}\n${conceptsList}`;
    }).join('\n\n');

    const responseText = `✅ Учебный план создан!\n\n${planText}\n\nОтправьте "да" для начала обучения.`;

    return [{
      json: {
        action: 'direct_response',
        telegram_text: responseText,
        chat_id: chatId,
        original_response: aiResponse
      }
    }];
  }

  return [{
    json: {
      action: 'direct_response',
      telegram_text: "Учебный план готов! Отправьте 'да' для начала обучения.",
      chat_id: chatId,
      original_response: aiResponse
    }
  }];
}

// 8. Это обычный ответ (приветствие, вопрос и т.д.)
console.log("📝 Отправляем прямой ответ пользователю");
return [{
  json: {
    action: 'direct_response',
    telegram_text: aiResponse,
    chat_id: chatId,
    original_response: aiResponse
  }
}];

