  console.log(`  Ответ содержит answer: ${!!tavilyResponse.answer}`);
  console.log(`  Ответ содержит results: ${tavilyResponse.results ? tavilyResponse.results.length : 0}`);

  // 3. Подготавливаем данные для AI Agent1
  const preparedData = {
    chat_id: chatId,
    search_query: searchQuery,
    answer: tavilyResponse.answer || "",
    results: tavilyResponse.results || []
  };

  console.log("✅ Данные подготовлены для AI Agent1");
  console.log(`  Answer length: ${preparedData.answer.length} символов`);
  console.log(`  Results: ${preparedData.results.length} результатов`);

  // 4. ОТЛАДКА: Показываем первый результат
  if (preparedData.results.length > 0) {
    console.log("📄 Первый результат:");
    console.log(`  Title: ${preparedData.results[0].title}`);
    console.log(`  Content: ${preparedData.results[0].content.substring(0, 100)}...`);
  }

  return [{
    json: {
      ...preparedData,
      debug: {
        parsed_successfully: true,
        results_count: preparedData.results.length,
        answer_exists: !!preparedData.answer,
        chat_id: chatId,
        timestamp: new Date().toISOString()
      }
    }
  }];

} catch (error) {
  console.error("❌ Ошибка парсинга Tavily:", error);

  return [{
    json: {
      chat_id: "error",
      search_query: "Ошибка запроса",
      answer: `Ошибка при обработке ответа Tavily: ${error.message}`,
      results: [],
      error: error.message,
      debug: {
        parsed_successfully: false,
        error: true
      }
    }
  }];
}
